definition.script:
import groovy.json.JsonSlurper;
import groovy.json.JsonOutput;

def new_policy
pipeline {
    agent any 
    stages {
        stage('Retrieve Build Spec') { 
            steps {
                script {
                    sh 'aws s3api get-bucket-policy --bucket ${stack_s3_bucket} --query Policy --output text > /tmp/policy.json'
                    def bucket_policy = new JsonSlurper().parse(new File('/tmp/policy.json'))
                    def statements_to_remove = [];
                    def target_stack = "$target_stack"
                    def stack_githash = "$stack_githash"
                    for(def statement : bucket_policy.Statement){
                        if(statement.Sid!=null && statement.Sid.startsWith("stack-"+target_stack+"-statement")
                        ||statement.Principal.AWS.size()<22){
                            // This is an identifier that AWS uses for deleted stuff... not really sure past that
                            statements_to_remove.push(statement)
                        }
                    }
                    bucket_policy.Statement.removeAll(statements_to_remove)
                    bucket_policy.Statement.push(new JsonSlurper().parseText("{\"Sid\": \"stack-"+target_stack+"-statement-open-hpds\", \"Effect\": \"Allow\",\"Principal\": {\"AWS\": \"arn:aws:iam::$aws_account_app:role/open-hpds-deployment-s3-role-" + target_stack + "-" + stack_githash.substring(0,7) + "\"},\"Action\": \"s3:GetObject\",\"Resource\": \"arn:aws:s3:::${stack_s3_bucket}/*\"}"));
                    bucket_policy.Statement.push(new JsonSlurper().parseText("{\"Sid\": \"stack-"+target_stack+"-statement-auth-hpds\", \"Effect\": \"Allow\",\"Principal\": {\"AWS\": \"arn:aws:iam::$aws_account_app:role/auth-hpds-deployment-s3-role-" + target_stack + "-" + stack_githash.substring(0,7) + "\"},\"Action\": \"s3:GetObject\",\"Resource\": \"arn:aws:s3:::${stack_s3_bucket}/*\"}"));
                    bucket_policy.Statement.push(new JsonSlurper().parseText("{\"Sid\": \"stack-"+target_stack+"-statement-wildfly\", \"Effect\": \"Allow\",\"Principal\": {\"AWS\": \"arn:aws:iam::$aws_account_app:role/wildfly-deployment-s3-role-" + target_stack + "-" + stack_githash.substring(0,7) + "\"},\"Action\": \"s3:GetObject\",\"Resource\": \"arn:aws:s3:::${stack_s3_bucket}/*\"}"));
                    bucket_policy.Statement.push(new JsonSlurper().parseText("{\"Sid\": \"stack-"+target_stack+"-statement-httpd\", \"Effect\": \"Allow\",\"Principal\": {\"AWS\": \"arn:aws:iam::$aws_account_app:role/httpd-deployment-s3-role-" + target_stack + "-" + stack_githash.substring(0,7) + "\"},\"Action\": \"s3:GetObject\",\"Resource\": \"arn:aws:s3:::${stack_s3_bucket}/*\"}"));
                    bucket_policy.Statement.push(new JsonSlurper().parseText("{\"Sid\": \"stack-"+target_stack+"-statement-dictionary\", \"Effect\": \"Allow\",\"Principal\": {\"AWS\": \"arn:aws:iam::$aws_account_app:role/dictionary-deployment-s3-role-" + target_stack + "-" + stack_githash.substring(0,7) + "\"},\"Action\": \"s3:GetObject\",\"Resource\": \"arn:aws:s3:::${stack_s3_bucket}/*\"}"));

                    new_policy = new JsonOutput().toJson(bucket_policy)

                }
                script{
                    println(new_policy)
                    println('writing file')
                    writeFile file: 'new_policy.json', text: new_policy
                    println('forming command')
                    def command = "aws s3api put-bucket-policy --bucket ${stack_s3_bucket} --policy file://new_policy.json"
                    println('pushing file')
                    println command
                    sh command
                    println('pushed file')
                }
            }
        }
    }
}
